-- Repair historical plan tasks that were generated by enroll_testees_after_date
-- and then accidentally opened/completed "now".
--
-- Scope:
--   MySQL-side repair only. AnswerSheet and interpret report documents are in MongoDB
--   and must be repaired separately with the exported mapping at the bottom.
--
-- Before running:
--   1. Change the variables below.
--   2. Run sections 1 and 2 first, inspect the preview rows/counts.
--   3. Only then run sections 3 and 4.

SET NAMES utf8mb4 COLLATE utf8mb4_unicode_ci;
SET collation_connection = 'utf8mb4_unicode_ci';
SET SQL_SAFE_UPDATES = 0;

-- =========================
-- 1. Parameters
-- =========================

SET @org_id = 1;
SET @plan_id = 614333603412718126;

-- The time window when enroll_testees_after_date created the historical tasks.
-- Narrow this as much as possible. Use the actual script run time window.
SET @task_created_start = '2026-04-25 00:00:00';
SET @task_created_end   = '2026-04-26 00:00:00';

-- Optional planned_at window. Keep NULL if task_created window is already precise.
SET @planned_start = NULL;
SET @planned_end   = NULL;

-- Default synthetic durations when the original bad data cannot provide a sane delay.
SET @default_complete_delay_seconds = 300; -- task open -> completed/submitted: 5 minutes
SET @default_assessment_create_delay_seconds = 30;
SET @default_interpret_delay_seconds = 60;
SET @expire_after_days = 7;

-- =========================
-- 2. Build and inspect scope
-- =========================

DROP TEMPORARY TABLE IF EXISTS `repair_plan_task_time_scope`;

CREATE TEMPORARY TABLE `repair_plan_task_time_scope`
DEFAULT CHARSET=utf8mb4
COLLATE=utf8mb4_unicode_ci
AS
SELECT
  base.`task_id`,
  base.`org_id`,
  base.`plan_id`,
  base.`testee_id`,
  base.`assessment_id`,
  base.`answer_sheet_id`,
  base.`episode_id`,
  base.`report_id`,
  base.`entry_id`,
  base.`clinician_id`,

  base.`planned_at`,
  base.`old_task_created_at`,
  base.`old_task_updated_at`,
  base.`old_open_at`,
  base.`old_expire_at`,
  base.`old_completed_at`,
  base.`old_assessment_created_at`,
  base.`old_assessment_updated_at`,
  base.`old_assessment_submitted_at`,
  base.`old_assessment_interpreted_at`,
  base.`old_score_created_at`,
  base.`old_score_updated_at`,
  base.`old_episode_submitted_at`,
  base.`old_episode_assessment_created_at`,
  base.`old_episode_report_generated_at`,

  base.`complete_delay_seconds`,
  base.`assessment_create_delay_seconds`,
  base.`interpret_delay_seconds`,

  base.`planned_at` AS `new_open_at`,
  DATE_ADD(base.`planned_at`, INTERVAL @expire_after_days DAY) AS `new_expire_at`,
  DATE_ADD(base.`planned_at`, INTERVAL base.`complete_delay_seconds` SECOND) AS `new_completed_at`,
  DATE_ADD(base.`planned_at`, INTERVAL base.`complete_delay_seconds` SECOND) AS `new_submitted_at`,
  DATE_ADD(
    DATE_ADD(base.`planned_at`, INTERVAL base.`complete_delay_seconds` SECOND),
    INTERVAL base.`assessment_create_delay_seconds` SECOND
  ) AS `new_assessment_created_at`,
  CASE
    WHEN base.`old_assessment_interpreted_at` IS NULL THEN NULL
    ELSE DATE_ADD(
      DATE_ADD(
        DATE_ADD(base.`planned_at`, INTERVAL base.`complete_delay_seconds` SECOND),
        INTERVAL base.`assessment_create_delay_seconds` SECOND
      ),
      INTERVAL base.`interpret_delay_seconds` SECOND
    )
  END AS `new_interpreted_at`,
  CASE
    WHEN base.`old_episode_report_generated_at` IS NULL THEN NULL
    ELSE DATE_ADD(
      DATE_ADD(
        DATE_ADD(base.`planned_at`, INTERVAL base.`complete_delay_seconds` SECOND),
        INTERVAL base.`assessment_create_delay_seconds` SECOND
      ),
      INTERVAL base.`interpret_delay_seconds` SECOND
    )
  END AS `new_report_generated_at`
FROM (
  SELECT
    t.`id` AS `task_id`,
    t.`org_id`,
    t.`plan_id`,
    t.`testee_id`,
    t.`assessment_id`,
    a.`answer_sheet_id`,
    e.`episode_id`,
    e.`report_id`,
    COALESCE(e.`entry_id`, 0) AS `entry_id`,
    COALESCE(e.`clinician_id`, 0) AS `clinician_id`,

    t.`planned_at`,
    t.`created_at` AS `old_task_created_at`,
    t.`updated_at` AS `old_task_updated_at`,
    t.`open_at` AS `old_open_at`,
    t.`expire_at` AS `old_expire_at`,
    t.`completed_at` AS `old_completed_at`,
    a.`created_at` AS `old_assessment_created_at`,
    a.`updated_at` AS `old_assessment_updated_at`,
    a.`submitted_at` AS `old_assessment_submitted_at`,
    a.`interpreted_at` AS `old_assessment_interpreted_at`,
    MIN(sc.`created_at`) AS `old_score_created_at`,
    MAX(sc.`updated_at`) AS `old_score_updated_at`,
    e.`submitted_at` AS `old_episode_submitted_at`,
    e.`assessment_created_at` AS `old_episode_assessment_created_at`,
    e.`report_generated_at` AS `old_episode_report_generated_at`,

    CASE
      WHEN t.`open_at` IS NOT NULL
        AND t.`completed_at` IS NOT NULL
        AND TIMESTAMPDIFF(SECOND, t.`open_at`, t.`completed_at`) BETWEEN 0 AND 86400
      THEN GREATEST(60, TIMESTAMPDIFF(SECOND, t.`open_at`, t.`completed_at`))
      ELSE @default_complete_delay_seconds
    END AS `complete_delay_seconds`,

    CASE
      WHEN a.`submitted_at` IS NOT NULL
        AND a.`created_at` IS NOT NULL
        AND TIMESTAMPDIFF(SECOND, a.`submitted_at`, a.`created_at`) BETWEEN 0 AND 3600
      THEN TIMESTAMPDIFF(SECOND, a.`submitted_at`, a.`created_at`)
      ELSE @default_assessment_create_delay_seconds
    END AS `assessment_create_delay_seconds`,

    CASE
      WHEN a.`created_at` IS NOT NULL
        AND a.`interpreted_at` IS NOT NULL
        AND TIMESTAMPDIFF(SECOND, a.`created_at`, a.`interpreted_at`) BETWEEN 0 AND 86400
      THEN GREATEST(1, TIMESTAMPDIFF(SECOND, a.`created_at`, a.`interpreted_at`))
      ELSE @default_interpret_delay_seconds
    END AS `interpret_delay_seconds`
  FROM `assessment_task` t
  INNER JOIN `assessment` a
    ON a.`id` = t.`assessment_id`
   AND a.`deleted_at` IS NULL
  LEFT JOIN `assessment_score` sc
    ON sc.`assessment_id` = a.`id`
   AND sc.`deleted_at` IS NULL
  LEFT JOIN `assessment_episode` e
    ON e.`answersheet_id` = a.`answer_sheet_id`
   AND e.`deleted_at` IS NULL
  WHERE t.`org_id` = @org_id
    AND t.`plan_id` = @plan_id
    AND t.`deleted_at` IS NULL
    AND t.`status` COLLATE utf8mb4_unicode_ci = 'completed' COLLATE utf8mb4_unicode_ci
    AND t.`assessment_id` IS NOT NULL
    AND t.`created_at` >= @task_created_start
    AND t.`created_at` < @task_created_end
    AND (@planned_start IS NULL OR t.`planned_at` >= @planned_start)
    AND (@planned_end IS NULL OR t.`planned_at` < @planned_end)
    AND a.`origin_type` COLLATE utf8mb4_unicode_ci = 'plan' COLLATE utf8mb4_unicode_ci
    AND a.`origin_id` COLLATE utf8mb4_unicode_ci = CAST(@plan_id AS CHAR) COLLATE utf8mb4_unicode_ci
  GROUP BY
    t.`id`, t.`org_id`, t.`plan_id`, t.`testee_id`, t.`assessment_id`, a.`answer_sheet_id`,
    e.`episode_id`, e.`report_id`, e.`entry_id`, e.`clinician_id`,
    t.`planned_at`, t.`created_at`, t.`updated_at`, t.`open_at`, t.`expire_at`, t.`completed_at`,
    a.`created_at`, a.`updated_at`, a.`submitted_at`, a.`interpreted_at`,
    e.`submitted_at`, e.`assessment_created_at`, e.`report_generated_at`
) base;

SELECT
  COUNT(*) AS `task_count`,
  COUNT(DISTINCT `testee_id`) AS `testee_count`,
  COUNT(DISTINCT `assessment_id`) AS `assessment_count`,
  COUNT(DISTINCT `answer_sheet_id`) AS `answersheet_count`,
  MIN(`planned_at`) AS `min_planned_at`,
  MAX(`planned_at`) AS `max_planned_at`,
  MIN(`old_completed_at`) AS `min_old_completed_at`,
  MAX(`old_completed_at`) AS `max_old_completed_at`,
  MIN(`new_completed_at`) AS `min_new_completed_at`,
  MAX(`new_completed_at`) AS `max_new_completed_at`
FROM `repair_plan_task_time_scope`;

SELECT
  `task_id`, `testee_id`, `assessment_id`, `answer_sheet_id`,
  `planned_at`,
  `old_open_at`, `old_completed_at`, `old_assessment_created_at`, `old_assessment_interpreted_at`,
  `new_open_at`, `new_completed_at`, `new_assessment_created_at`, `new_interpreted_at`
FROM `repair_plan_task_time_scope`
ORDER BY `planned_at`, `task_id`
LIMIT 50;

-- Stop here if the preview scope is not exactly the bad batch you want to repair.

-- =========================
-- 3. Backups
-- =========================
-- Change the 20260425 suffix if re-running.

CREATE TABLE `repair_bak_assessment_task_20260425` AS
SELECT t.*
FROM `assessment_task` t
INNER JOIN `repair_plan_task_time_scope` s ON s.`task_id` = t.`id`;

CREATE TABLE `repair_bak_assessment_20260425` AS
SELECT a.*
FROM `assessment` a
INNER JOIN `repair_plan_task_time_scope` s ON s.`assessment_id` = a.`id`;

CREATE TABLE `repair_bak_assessment_score_20260425` AS
SELECT sc.*
FROM `assessment_score` sc
INNER JOIN `repair_plan_task_time_scope` s ON s.`assessment_id` = sc.`assessment_id`
WHERE sc.`deleted_at` IS NULL;

CREATE TABLE `repair_bak_assessment_episode_20260425` AS
SELECT e.*
FROM `assessment_episode` e
INNER JOIN `repair_plan_task_time_scope` s ON s.`answer_sheet_id` = e.`answersheet_id`
WHERE e.`deleted_at` IS NULL;

CREATE TABLE `repair_bak_behavior_footprint_20260425` AS
SELECT bf.*
FROM `behavior_footprint` bf
INNER JOIN `repair_plan_task_time_scope` s
  ON s.`answer_sheet_id` = bf.`answersheet_id`
  OR s.`assessment_id` = bf.`assessment_id`
WHERE bf.`org_id` = @org_id
  AND bf.`deleted_at` IS NULL
  AND bf.`event_name` COLLATE utf8mb4_unicode_ci IN (
    'answersheet_submitted' COLLATE utf8mb4_unicode_ci,
    'assessment_created' COLLATE utf8mb4_unicode_ci,
    'report_generated' COLLATE utf8mb4_unicode_ci
  );

-- =========================
-- 4. Repair MySQL write models and journey read models
-- =========================

START TRANSACTION;

UPDATE `assessment_task` t
INNER JOIN `repair_plan_task_time_scope` s ON s.`task_id` = t.`id`
SET
  t.`open_at` = s.`new_open_at`,
  t.`expire_at` = s.`new_expire_at`,
  t.`completed_at` = s.`new_completed_at`,
  t.`updated_at` = NOW(3),
  t.`version` = t.`version` + 1;

UPDATE `assessment` a
INNER JOIN `repair_plan_task_time_scope` s ON s.`assessment_id` = a.`id`
SET
  a.`created_at` = s.`new_assessment_created_at`,
  a.`submitted_at` = s.`new_submitted_at`,
  a.`interpreted_at` = CASE
    WHEN a.`interpreted_at` IS NULL THEN NULL
    ELSE s.`new_interpreted_at`
  END,
  a.`updated_at` = NOW(3),
  a.`version` = a.`version` + 1;

UPDATE `assessment_score` sc
INNER JOIN `repair_plan_task_time_scope` s ON s.`assessment_id` = sc.`assessment_id`
SET
  sc.`created_at` = s.`new_assessment_created_at`,
  sc.`updated_at` = NOW(3),
  sc.`version` = sc.`version` + 1
WHERE sc.`deleted_at` IS NULL;

UPDATE `assessment_episode` e
INNER JOIN `repair_plan_task_time_scope` s ON s.`answer_sheet_id` = e.`answersheet_id`
SET
  e.`submitted_at` = s.`new_submitted_at`,
  e.`assessment_created_at` = CASE
    WHEN e.`assessment_created_at` IS NULL THEN NULL
    ELSE s.`new_assessment_created_at`
  END,
  e.`report_generated_at` = CASE
    WHEN e.`report_generated_at` IS NULL THEN NULL
    ELSE s.`new_report_generated_at`
  END,
  e.`updated_at` = NOW(3)
WHERE e.`deleted_at` IS NULL;

UPDATE `behavior_footprint` bf
INNER JOIN `repair_plan_task_time_scope` s
  ON s.`answer_sheet_id` = bf.`answersheet_id`
SET
  bf.`occurred_at` = CASE bf.`event_name` COLLATE utf8mb4_unicode_ci
    WHEN 'answersheet_submitted' COLLATE utf8mb4_unicode_ci THEN s.`new_submitted_at`
    WHEN 'assessment_created' COLLATE utf8mb4_unicode_ci THEN s.`new_assessment_created_at`
    WHEN 'report_generated' COLLATE utf8mb4_unicode_ci THEN s.`new_report_generated_at`
    ELSE bf.`occurred_at`
  END,
  bf.`updated_at` = NOW(3)
WHERE bf.`org_id` = @org_id
  AND bf.`deleted_at` IS NULL
  AND bf.`event_name` COLLATE utf8mb4_unicode_ci IN (
    'answersheet_submitted' COLLATE utf8mb4_unicode_ci,
    'assessment_created' COLLATE utf8mb4_unicode_ci,
    'report_generated' COLLATE utf8mb4_unicode_ci
  )
  AND (
    bf.`event_name` COLLATE utf8mb4_unicode_ci <> 'report_generated' COLLATE utf8mb4_unicode_ci
    OR s.`new_report_generated_at` IS NOT NULL
  );

-- Adjust analytics daily projections by delta instead of deleting full daily rows.
-- This keeps unrelated counters on the same date intact.

DROP TEMPORARY TABLE IF EXISTS `repair_plan_task_projection_delta`;

CREATE TEMPORARY TABLE `repair_plan_task_projection_delta`
DEFAULT CHARSET=utf8mb4
COLLATE=utf8mb4_unicode_ci
AS
SELECT
  d.`org_id`,
  d.`clinician_id`,
  d.`entry_id`,
  d.`stat_date`,
  SUM(d.`answersheet_submitted_delta`) AS `answersheet_submitted_delta`,
  SUM(d.`assessment_created_delta`) AS `assessment_created_delta`,
  SUM(d.`report_generated_delta`) AS `report_generated_delta`,
  SUM(d.`episode_completed_delta`) AS `episode_completed_delta`
FROM (
  SELECT
    s.`org_id`,
    s.`clinician_id`,
    s.`entry_id`,
    DATE(s.`old_episode_submitted_at`) AS `stat_date`,
    -1 AS `answersheet_submitted_delta`,
    0 AS `assessment_created_delta`,
    0 AS `report_generated_delta`,
    0 AS `episode_completed_delta`
  FROM `repair_plan_task_time_scope` s
  WHERE s.`old_episode_submitted_at` IS NOT NULL

  UNION ALL

  SELECT
    s.`org_id`, s.`clinician_id`, s.`entry_id`, DATE(s.`new_submitted_at`),
    1, 0, 0, 0
  FROM `repair_plan_task_time_scope` s

  UNION ALL

  SELECT
    s.`org_id`, s.`clinician_id`, s.`entry_id`, DATE(s.`old_episode_report_generated_at`),
    0, -1, -1, -1
  FROM `repair_plan_task_time_scope` s
  WHERE s.`old_episode_report_generated_at` IS NOT NULL

  UNION ALL

  SELECT
    s.`org_id`, s.`clinician_id`, s.`entry_id`, DATE(s.`new_report_generated_at`),
    0, 1, 1, 1
  FROM `repair_plan_task_time_scope` s
  WHERE s.`new_report_generated_at` IS NOT NULL
) d
WHERE d.`stat_date` IS NOT NULL
GROUP BY d.`org_id`, d.`clinician_id`, d.`entry_id`, d.`stat_date`;

INSERT INTO `analytics_projection_org_daily` (
  `org_id`, `stat_date`,
  `entry_opened_count`, `intake_confirmed_count`, `testee_profile_created_count`,
  `care_relationship_established_count`, `care_relationship_transferred_count`,
  `answersheet_submitted_count`, `assessment_created_count`, `report_generated_count`,
  `episode_completed_count`, `episode_failed_count`,
  `created_at`, `updated_at`
)
SELECT
  d.`org_id`, d.`stat_date`,
  0, 0, 0, 0, 0,
  d.`answersheet_submitted_delta`, d.`assessment_created_delta`, d.`report_generated_delta`,
  d.`episode_completed_delta`, 0,
  NOW(3), NOW(3)
FROM `repair_plan_task_projection_delta` d
ON DUPLICATE KEY UPDATE
  `answersheet_submitted_count` = `answersheet_submitted_count` + VALUES(`answersheet_submitted_count`),
  `assessment_created_count` = `assessment_created_count` + VALUES(`assessment_created_count`),
  `report_generated_count` = `report_generated_count` + VALUES(`report_generated_count`),
  `episode_completed_count` = `episode_completed_count` + VALUES(`episode_completed_count`),
  `updated_at` = NOW(3);

INSERT INTO `analytics_projection_clinician_daily` (
  `org_id`, `clinician_id`, `stat_date`,
  `entry_opened_count`, `intake_confirmed_count`, `testee_profile_created_count`,
  `care_relationship_established_count`, `care_relationship_transferred_count`,
  `answersheet_submitted_count`, `assessment_created_count`, `report_generated_count`,
  `episode_completed_count`, `episode_failed_count`,
  `created_at`, `updated_at`
)
SELECT
  d.`org_id`, d.`clinician_id`, d.`stat_date`,
  0, 0, 0, 0, 0,
  d.`answersheet_submitted_delta`, d.`assessment_created_delta`, d.`report_generated_delta`,
  d.`episode_completed_delta`, 0,
  NOW(3), NOW(3)
FROM `repair_plan_task_projection_delta` d
WHERE d.`clinician_id` <> 0
ON DUPLICATE KEY UPDATE
  `answersheet_submitted_count` = `answersheet_submitted_count` + VALUES(`answersheet_submitted_count`),
  `assessment_created_count` = `assessment_created_count` + VALUES(`assessment_created_count`),
  `report_generated_count` = `report_generated_count` + VALUES(`report_generated_count`),
  `episode_completed_count` = `episode_completed_count` + VALUES(`episode_completed_count`),
  `updated_at` = NOW(3);

INSERT INTO `analytics_projection_entry_daily` (
  `org_id`, `entry_id`, `clinician_id`, `stat_date`,
  `entry_opened_count`, `intake_confirmed_count`, `testee_profile_created_count`,
  `care_relationship_established_count`, `care_relationship_transferred_count`,
  `answersheet_submitted_count`, `assessment_created_count`, `report_generated_count`,
  `episode_completed_count`, `episode_failed_count`,
  `created_at`, `updated_at`
)
SELECT
  d.`org_id`, d.`entry_id`, d.`clinician_id`, d.`stat_date`,
  0, 0, 0, 0, 0,
  d.`answersheet_submitted_delta`, d.`assessment_created_delta`, d.`report_generated_delta`,
  d.`episode_completed_delta`, 0,
  NOW(3), NOW(3)
FROM `repair_plan_task_projection_delta` d
WHERE d.`entry_id` <> 0
ON DUPLICATE KEY UPDATE
  `clinician_id` = VALUES(`clinician_id`),
  `answersheet_submitted_count` = `answersheet_submitted_count` + VALUES(`answersheet_submitted_count`),
  `assessment_created_count` = `assessment_created_count` + VALUES(`assessment_created_count`),
  `report_generated_count` = `report_generated_count` + VALUES(`report_generated_count`),
  `episode_completed_count` = `episode_completed_count` + VALUES(`episode_completed_count`),
  `updated_at` = NOW(3);

-- Plan statistics are task-table aggregates. Rebuild just this plan row.
DELETE FROM `statistics_plan`
WHERE `org_id` = @org_id
  AND `plan_id` = @plan_id;

INSERT INTO `statistics_plan` (
  `org_id`, `plan_id`, `total_tasks`, `completed_tasks`, `pending_tasks`,
  `expired_tasks`, `enrolled_testees`, `active_testees`, `last_updated_at`
)
SELECT
  t.`org_id`,
  t.`plan_id`,
  COUNT(*) AS `total_tasks`,
  SUM(CASE WHEN t.`status` COLLATE utf8mb4_unicode_ci = 'completed' COLLATE utf8mb4_unicode_ci THEN 1 ELSE 0 END) AS `completed_tasks`,
  SUM(CASE WHEN t.`status` COLLATE utf8mb4_unicode_ci IN ('pending' COLLATE utf8mb4_unicode_ci, 'opened' COLLATE utf8mb4_unicode_ci) THEN 1 ELSE 0 END) AS `pending_tasks`,
  SUM(CASE WHEN t.`status` COLLATE utf8mb4_unicode_ci = 'expired' COLLATE utf8mb4_unicode_ci THEN 1 ELSE 0 END) AS `expired_tasks`,
  COUNT(DISTINCT t.`testee_id`) AS `enrolled_testees`,
  COUNT(DISTINCT CASE WHEN t.`status` COLLATE utf8mb4_unicode_ci = 'completed' COLLATE utf8mb4_unicode_ci THEN t.`testee_id` END) AS `active_testees`,
  NOW()
FROM `assessment_task` t
WHERE t.`org_id` = @org_id
  AND t.`plan_id` = @plan_id
  AND t.`deleted_at` IS NULL
GROUP BY t.`org_id`, t.`plan_id`;

COMMIT;

-- =========================
-- 5. Verification
-- =========================

SELECT
  COUNT(*) AS `repaired_task_count`,
  MIN(t.`planned_at`) AS `min_planned_at`,
  MAX(t.`planned_at`) AS `max_planned_at`,
  MIN(t.`open_at`) AS `min_open_at`,
  MAX(t.`open_at`) AS `max_open_at`,
  MIN(t.`completed_at`) AS `min_completed_at`,
  MAX(t.`completed_at`) AS `max_completed_at`
FROM `assessment_task` t
INNER JOIN `repair_plan_task_time_scope` s ON s.`task_id` = t.`id`;

SELECT
  t.`id` AS `task_id`,
  t.`planned_at`,
  t.`open_at`,
  t.`expire_at`,
  t.`completed_at`,
  a.`created_at` AS `assessment_created_at`,
  a.`submitted_at`,
  a.`interpreted_at`,
  e.`submitted_at` AS `episode_submitted_at`,
  e.`assessment_created_at` AS `episode_assessment_created_at`,
  e.`report_generated_at` AS `episode_report_generated_at`
FROM `repair_plan_task_time_scope` s
INNER JOIN `assessment_task` t ON t.`id` = s.`task_id`
INNER JOIN `assessment` a ON a.`id` = s.`assessment_id`
LEFT JOIN `assessment_episode` e ON e.`answersheet_id` = s.`answer_sheet_id`
ORDER BY t.`planned_at`, t.`id`
LIMIT 50;

-- Export this mapping for the Mongo repair:
--   answersheets.domain_id: filled_at, created_at, updated_at -> new_submitted_at
--   interpret_reports.domain_id: created_at, updated_at -> new_report_generated_at
SELECT
  `answer_sheet_id`,
  `assessment_id`,
  `new_submitted_at`,
  `new_assessment_created_at`,
  `new_interpreted_at`,
  `new_report_generated_at`
FROM `repair_plan_task_time_scope`
ORDER BY `answer_sheet_id`;
